  ('optometrist-moex-01793', 'optometrist', 'optometrist-moex-109-ddcf1380', 'sub-optometrist-04', NULL, 'single_choice', '眼鏡處方-3.00DS/+6.00DC×180代表的屈光狀態在分類上屬於下列何者？', '["複合性遠視散光（compoundhyperopicastigmatism）", "複合性近視散光（compoundmyopicastigmatism）", "混合性散光（mixedastigmatism）", "單純性遠視散光（simplehyperopicastigmatism）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:49+00:00", "source_pdf_sha1": "ce0dc77563b8", "answer_pdf_sha1": "a1c83f3335a4", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "112", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視覺光學", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL)
